// count. The parent of the share root is not registered, so it is ignored.
func (a *shareAgg) bumpParent(path string) {
	parent := filepath.Dir(path)
	if parent == path {
		return
	}
	if _, ok := a.dirChildCount[parent]; ok {
		a.dirChildCount[parent]++
	}
