// itoa avoids importing strconv just for the test loop labels.
func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	var b []byte
	for n > 0 {
		b = append([]byte{byte('0' + n%10)}, b...)
		n /= 10
	}
	return string(b)
}
package jobs

import (
	"os"
	"path/filepath"
	"testing"
