+	dirs := make([]string, 0, len(job.DirMtimes))
+	for rel := range job.DirMtimes {
+		dirs = append(dirs, rel)
+	}
+	sort.Slice(dirs, func(i, j int) bool { return len(dirs[i]) > len(dirs[j]) })
