+func (m *Manager) RepairDirMtimesFromSnapshot(id string) (*MoveJob, []byte, error) {
+	job, err := m.store.LoadMoveJob(id)
+	if err != nil {
+		return nil, nil, ErrNotFound
+	}
+	if job.SnapshotPath == "" {
+		return nil, nil, fmt.Errorf("%w: job has no snapshot_path", ErrMoveState)
