+func relDirAncestors(relFile string) []string {
+	rel := filepath.ToSlash(filepath.Dir(filepath.FromSlash(relFile)))
+	if rel == "." || rel == "" {
+		return nil
+	}
+	var out []string
+	for rel != "." && rel != "" {
+		out = append(out, rel)
+		parent := filepath.ToSlash(filepath.Dir(filepath.FromSlash(rel)))
+		if parent == rel {
+			break
+		}
+		rel = parent
+	}
+	return out
+}
