{"cmd":"ssh -o BatchMode=yes -o ConnectTimeout=10 -p 1904 ahazan@100.107.131.36 "cat > /tmp/edges2_layered_timestamp_audit.py" <<'PY'
import csv
import hashlib
import os
import re
import sys
import time
from collections import Counter

root = "/volume1/mac"
snap_root = "/volume1/mac/#snapshot"
out_dir = "/tmp/synology_layered_timestamp_audit_20260615"
os.makedirs(out_dir, exist_ok=True)

current_after = int(time.mktime((2024, 1, 1, 0, 0, 0, 0, 0, -1)))
old_before = current_after
min_jump_seconds = 30 * 24 * 60 * 60
hash_max_file = 512 * 1024 * 1024
hash_budget = 30 * 1024 * 1024 * 1024
xmp_read_limit = 3 * 1024 * 1024
skip_dirs = {"#snapshot", "@eaDir", ".SynologyWorkingDirectory", ".sync"}
xmp_exts = {".psd", ".psb", ".ai", ".pdf"}
xmp_re = re.compile(rb"<xmp:(CreateDate|ModifyDate|MetadataDate)>([^<]+)</xmp:[^>]+>")

def fmt(ts):
    return time.strftime("%Y-%m-%d %H:%M:%S %z", time.localtime(ts))

def parse_xmp_date(raw):
    s = raw.decode("utf-8", "ignore").strip()
    for layout in ("%Y-%m-%dT%H:%M:%S%z", "%Y:%m:%d %H:%M:%S"):
        try:
            return int(time.mktime(time.strptime(s, layout))) if layout.endswith("%S") else int(time.strptime(s, layout).timestamp())
        except Exception:
            pass
    # Python's strptime handles offsets without colon on some systems but not all.
    try:
        if len(s) >= 25 and (s[-6] in "+-" and s[-3] == ":"):
            compact = s[:-3] + s[-2:]
            return int(time.strptime(compact, "%Y-%m-%dT%H:%M:%S%z").timestamp())
    except Exception:
        pass
    return None

def xmp_old_evidence(path, cur_mtime):
    ext = os.path.splitext(path)[1].lower()
    if ext not in xmp_exts:
        return None
    try:
        with open(path, "rb") as f:
            data = f.read(xmp_read_limit)
    except OSError:
        return None
    found = {}
    newest = None
    for key, val in xmp_re.findall(data):
        name = key.decode("ascii", "ignore")
        value = val.decode("utf-8", "ignore").strip()
        found.setdefault(name, value)
        parsed = parse_xmp_date(val)
        if parsed is not None and (newest is None or parsed > newest):
            newest = parsed
    if newest is None or newest >= old_before or cur_mtime - newest < min_jump_seconds:
        return None
    ordered = []
    for k in ("ModifyDate", "MetadataDate", "CreateDate"):
        if k in found:
            ordered.append(f"{k}={found[k]}")
    return ";".join(ordered)

def sha256(path):
    h = hashlib.sha256()
    with open(path, "rb", buffering=1024*1024) as f:
        for chunk in iter(lambda: f.read(1024*1024), b""):
            h.update(chunk)
    return h.hexdigest()

snapshots = []
for name in sorted(os.listdir(snap_root)):
    path = os.path.join(snap_root, name)
    if os.path.isdir(path):
        snapshots.append((name, path))

paths = {
    "same_inode": os.path.join(out_dir, "tier2_same_inode_snapshot.csv"),
    "hash_match": os.path.join(out_dir, "tier1_hash_match_snapshot.csv"),
    "hash_mismatch": os.path.join(out_dir, "hash_mismatch_snapshot.csv"),
    "hash_pending": os.path.join(out_dir, "hash_pending_snapshot.csv"),
    "xmp": os.path.join(out_dir, "tier3_embedded_metadata.csv"),
    "summary": os.path.join(out_dir, "summary.txt"),
}

counts = Counter()
current_months = Counter()
snapshot_years = Counter()
top_dirs = Counter()
xmp_top_dirs = Counter()
hash_bytes = 0
start = time.time()

with open(paths["same_inode"], "w", newline="") as same_fh, \
     open(paths["hash_match"], "w", newline="") as match_fh, \
     open(paths["hash_mismatch"], "w", newline="") as mismatch_fh, \
     open(paths["hash_pending"], "w", newline="") as pending_fh, \
     open(paths["xmp"], "w", newline="") as xmp_fh:
    same_w = csv.writer(same_fh)
    match_w = csv.writer(match_fh)
    mismatch_w = csv.writer(mismatch_fh)
    pending_w = csv.writer(pending_fh)
    xmp_w = csv.writer(xmp_fh)
    header = ["rel", "current_mtime_epoch", "current_mtime", "snapshot", "snapshot_mtime_epoch", "snapshot_mtime", "size", "evidence", "sha256"]
    for w in (same_w, match_w, mismatch_w, pending_w):
        w.writerow(header)
    xmp_w.writerow(["rel", "current_mtime_epoch", "current_mtime", "size", "evidence"])

    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if d not in skip_dirs]
        if dirpath.startswith(root + "/#snapshot"):
            dirnames[:] = []
            continue
        for name in filenames:
            path = os.path.join(dirpath, name)
            counts["files_seen"] += 1
            try:
                st = os.lstat(path)
            except OSError:
                counts["stat_errors"] += 1
                continue
            if not os.path.isfile(path):
                continue
            if st.st_mtime < current_after:
                continue
            counts["too_new_since_2024"] += 1
            rel = os.path.relpath(path, root).replace(os.sep, "/")
            current_months[fmt(st.st_mtime)[:7]] += 1

            xmp = xmp_old_evidence(path, int(st.st_mtime))
            if xmp:
                counts["tier3_xmp_old"] += 1
                xmp_top_dirs["/".join(rel.split("/")[:3])] += 1
                xmp_w.writerow([rel, int(st.st_mtime), fmt(st.st_mtime), st.st_size, xmp])

            best = None
            same_inode_best = None
            for snap_name, snap_path in snapshots:
                sp = os.path.join(snap_path, rel)
                try:
                    sst = os.lstat(sp)
                except OSError:
                    continue
                if not os.path.isfile(sp):
                    continue
                if sst.st_size != st.st_size:
                    continue
                if sst.st_mtime >= old_before:
                    continue
                if st.st_mtime - sst.st_mtime < min_jump_seconds:
                    continue
                cand = (int(sst.st_mtime), snap_name, sp, sst)
                if best is None or cand[0] < best[0]:
                    best = cand
                if sst.st_ino == st.st_ino:
                    if same_inode_best is None or cand[0] < same_inode_best[0]:
                        same_inode_best = cand
            if same_inode_best:
                snap_mtime, snap_name, sp, sst = same_inode_best
                counts["tier2_same_inode"] += 1
                snapshot_years[fmt(snap_mtime)[:4]] += 1
                top_dirs["/".join(rel.split("/")[:3])] += 1
                same_w.writerow([rel, int(st.st_mtime), fmt(st.st_mtime), snap_name, snap_mtime, fmt(snap_mtime), st.st_size, "same_path_size_inode_old_snapshot", ""])
            elif best:
                snap_mtime, snap_name, sp, sst = best
                if st.st_size <= hash_max_file and hash_bytes + st.st_size * 2 <= hash_budget:
                    try:
                        cur_hash = sha256(path)
                        snap_hash = sha256(sp)
                        hash_bytes += st.st_size * 2
                    except OSError:
                        counts["hash_errors"] += 1
                        pending_w.writerow([rel, int(st.st_mtime), fmt(st.st_mtime), snap_name, snap_mtime, fmt(snap_mtime), st.st_size, "hash_error", ""])
                        continue
                    if cur_hash == snap_hash:
                        counts["tier1_hash_match"] += 1
                        snapshot_years[fmt(snap_mtime)[:4]] += 1
                        top_dirs["/".join(rel.split("/")[:3])] += 1
                        match_w.writerow([rel, int(st.st_mtime), fmt(st.st_mtime), snap_name, snap_mtime, fmt(snap_mtime), st.st_size, "same_path_size_hash_old_snapshot", cur_hash])
